IDENTIFIER_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

ALLOWED_OPERATORS = {
    "=": "=",
    "!=": "!=",
    "<>": "<>",
    ">": ">",
    ">=": ">=",
    "<": "<",
    "<=": "<=",
    "like": "LIKE",
    "ilike": "ILIKE",
    "in": "IN",
    "not in": "NOT IN",
    "is": "IS",
    "is not": "IS NOT",
}

ALLOWED_SORT_DIRECTIONS = {"asc": "ASC", "desc": "DESC"}


def get_connection():
    return psycopg2.connect(**DB_CONFIG)


def validate_identifier(name):
    if not isinstance(name, str) or not IDENTIFIER_RE.fullmatch(name):
        raise ValueError(f"Invalid identifier: {name}")
    return name


def validate_columns(columns):
    if columns is None:
        return []
    if not isinstance(columns, list):
        raise ValueError("columns must be a list")
    return [validate_identifier(col) for col in columns]


def validate_table(table):
    return validate_identifier(table)


def build_where_clause(filters):
    if not filters:
        return "", []

    if not isinstance(filters, list):
        raise ValueError("filters must be a list")

    clauses = []
    params = []

    for f in filters:
        if not isinstance(f, dict):
            raise ValueError("Each filter must be an object")

        column = validate_identifier(f.get("column"))
        operator = str(f.get("operator", "=")).strip().lower()
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Unsupported operator: {operator}")

        sql_op = ALLOWED_OPERATORS[operator]
        value = f.get("value")

        if operator in {"in", "not in"}:
            if not isinstance(value, list) or len(value) == 0:
                raise ValueError(f"{operator} requires a non-empty list value")
            placeholders = ", ".join(["%s"] * len(value))
            clauses.append(f"{column} {sql_op} ({placeholders})")
            params.extend(value)
        elif operator in {"is", "is not"}:
            if value is None:
                clauses.append(f"{column} {sql_op} NULL")
            elif isinstance(value, str) and value.upper() in {"NULL", "TRUE", "FALSE"}:
                clauses.append(f"{column} {sql_op} {value.upper()}")
            else:
                raise ValueError("IS / IS NOT only supports NULL, TRUE, FALSE, or None")
        else:
            clauses.append(f"{column} {sql_op} %s")
            params.append(value)

    return " WHERE " + " AND ".join(clauses), params


def build_order_clause(sort):
    if not sort:
        return ""

    if not isinstance(sort, list):
        raise ValueError("sort must be a list")

    parts = []
    for s in sort:
        if not isinstance(s, dict):
            raise ValueError("Each sort item must be an object")
        column = validate_identifier(s.get("column"))
        direction = str(s.get("direction", "asc")).strip().lower()
        if direction not in ALLOWED_SORT_DIRECTIONS:
            raise ValueError(f"Unsupported sort direction: {direction}")
        parts.append(f"{column} {ALLOWED_SORT_DIRECTIONS[direction]}")

    return " ORDER BY " + ", ".join(parts)


def build_limit_clause(limit, offset):
    clause = ""
    params = []

    if limit is not None:
        if not isinstance(limit, int) or limit < 1 or limit > 10000:
            raise ValueError("limit must be an integer between 1 and 10000")
        clause += " LIMIT %s"
        params.append(limit)

    if offset is not None:
        if not isinstance(offset, int) or offset < 0:
            raise ValueError("offset must be a non-negative integer")
        clause += " OFFSET %s"
        params.append(offset)

    return clause, params


@app.route("/query", methods=["POST"])
def query():
    try:
        payload = request.get_json(force=True, silent=False)
        if not isinstance(payload, dict):
            return jsonify({"error": "Request body must be a JSON object"}), 400

        table = validate_table(payload.get("table"))
        columns = validate_columns(payload.get("columns"))
        filters = payload.get("filters", [])
        sort = payload.get("sort", [])
        limit = payload.get("limit")
        offset = payload.get("offset")
        distinct = bool(payload.get("distinct", False))

        select_part = "*"
        if columns:
            select_part = ", ".join(columns)

        distinct_part = "DISTINCT " if distinct else ""
        where_clause, where_params = build_where_clause(filters)
        order_clause = build_order_clause(sort)
        limit_clause, limit_params = build_limit_clause(limit, offset)

        sql = f"SELECT {distinct_part}{select_part} FROM {table}{where_clause}{order_clause}{limit_clause}"
        params = where_params + limit_params

        conn = get_connection()
        try:
            with conn:
                with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                    cur.execute(sql, params)
                    rows = cur.fetchall()
            return jsonify({"data": rows, "count": len(rows), "sql": sql}), 200
        finally:
            conn.close()

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({"error": "Database error", "details": str(e)}), 500
    except Exception as e:
        return jsonify({"error": "Internal server error", "details": str(e)}), 500


